from typing import List


def separate_paren_groups(paren_string: str) -> List[str]:
    """ Input to this function is a string containing multiple groups of nested parentheses. Your goal is to
    separate those group into separate strings and return the list of those.
    Separate groups are balanced (each open brace is properly closed) and not nested within each other
    Ignore any spaces in the input string.
    >>> separate_paren_groups('( ) (( )) (( )( ))')
    ['()', '(())', '(()())']
    """
    result: List[str] = []
    paren_stack: List[str] = []
    paren_dict = {'(': ')', '[': ']', '{': '}'}

    for c in paren_string:
        if c == '(':
            paren_stack.append(c)
        elif c == ')':
            paren_stack.pop()
        elif c == '[':
            paren_stack.append(c)
        elif c == ']':
            paren_stack.pop()
        elif c == '{':
            paren_stack.append(c)
        elif c == '}':
            paren_stack.pop()
        elif c =='' or c == '\n' or c == '\t':
            pass
        else:
            raise ValueError(f'Invalid paren character: {c}')

    if paren_stack:
        raise ValueError('Invalid paren string, not balanced')

    index = 0
    paren_groups = []
    paren_group = []
    while index < len(paren_string):
        c = paren_string[index]
        if c == '(':
            paren_group.append(c)
        elif c == ')':
            paren_group.append(c)
        elif c == '[':
            paren_group.append(c)
        elif c == ']':
            paren_group.append(c)
        elif c == '{':
            paren_group.append(c)
        elif c == '}':
            paren_group.append(c)
        elif c =='' or c == '\n' or c == '\t':
            pass
        else:
            raise ValueError(f'Invalid paren character: {c}')
        if paren_dict[paren_group[0]] == c:
            paren_groups.append(paren_group)

