def all_prefixes(string: str) -> List[str]:
    """ Return list of all prefixes from shortest to longest of the input string
    >>> all_prefixes('abc')
    ['a', 'ab', 'abc']
    """
    if string == '':
        return ['']
    else:
        return [string[:i] for i in range(1, len(string) + 1)] + all_prefixes(string[:-1])
