def is_happy(s):
    """You are given a string s.
    Your task is to check if the string is happy or not.
    A string is happy if its length is at least 3 and every 3 consecutive letters are distinct
    For example:
    is_happy(a) => False
    is_happy(aa) => False
    is_happy(abcd) => True
    is_happy(aabb) => False
    is_happy(adb) => True
    is_happy(xyy) => False
    """
    count_dict = {}
    for c in s:
        count_dict[c] = count_dict.get(c, 0) + 1

    for c in s[::3]:
        count_dict[c] -= 1

    for c in s[1::3]:
        count_dict[c] -= 1

    for c in s[2::3]:
        count_dict[c] -= 1

    return all(v == 0 for v in count_dict.values())

